  36→// Request types
  37→export interface GetProductsParams {
  38→  page?: number;
  39→  pageSize?: number;
  40→  categoryId?: string;
  41→  status?: string;
  42→  search?: string;
  43→  sortBy?: string;
  44→  sortDirection?: string;
  45→}
