// Runtime-resolved API base URL (fetched once from /api/config)
let _configPromise: Promise<string> | null = null;

function getApiBase(): Promise<string> {
  if (!_configPromise) {
    _configPromise =
      typeof window !== "undefined"
        ? fetch("/api/config")
            .then((r) => r.json())
            .then((d) => d.apiBaseUrl as string)
            .catch(() => "http://localhost:5200")
        : Promise.resolve(
            process.env.NEXT_PUBLIC_API_URL || "http://localhost:5200"
          );
  }
  return _configPromise;
}

// Product types
export interface ProductDto {
  id: string;
  name: string;
  description: string;
  price: number;
  priceCurrency: string;
  imageUrl: string | null;
  sku: string | null;
  status: 'Draft' | 'Published' | 'Archived';
  categoryId: string;
  categoryName: string;
  averageRating: number | null;
  reviewCount: number;
  createdAt: string;
  updatedAt: string | null;
}

export interface ProductListDto {
  items: ProductDto[];
  totalCount: number;
  page: number;
  pageSize: number;
}

// Category types
export interface CategoryDto {
  id: string;
  name: string;
  description: string | null;
  createdAt: string;
}

// Request types
export interface GetProductsParams {
  page?: number;
  pageSize?: number;
  categoryId?: string;
  status?: string;
  search?: string;
  sortBy?: string;
  sortDirection?: string;
}

export interface CreateProductRequest {
  name: string;
  description: string;
  price: number;
  categoryId: string;
  imageUrl?: string;
  sku?: string;
}

export interface UpdateProductRequest extends CreateProductRequest {}

export interface CreateCategoryRequest {
  name: string;
  description?: string;
}

export interface UpdateCategoryRequest {
  name: string;
  description?: string;
}

// Product API functions
export async function getProducts(params: GetProductsParams = {}): Promise<ProductListDto> {
  const apiBase = await getApiBase();
  const searchParams = new URLSearchParams();
  if (params.page) searchParams.set('page', params.page.toString());
  if (params.pageSize) searchParams.set('pageSize', params.pageSize.toString());
  if (params.categoryId) searchParams.set('categoryId', params.categoryId);
  if (params.status) searchParams.set('status', params.status);
  if (params.search) searchParams.set('search', params.search);
  if (params.sortBy) searchParams.set('sortBy', params.sortBy);
  if (params.sortDirection) searchParams.set('sortDirection', params.sortDirection);

  const response = await fetch(`${apiBase}/api/catalog/products?${searchParams}`, {
    cache: 'no-store',
  });

  if (!response.ok) {
    throw new Error('Failed to fetch products');
  }

  return response.json();
}

export async function getProductById(id: string): Promise<ProductDto> {
  const apiBase = await getApiBase();
  const response = await fetch(`${apiBase}/api/catalog/products/${id}`, {
    cache: 'no-store',
  });

  if (!response.ok) {
    throw new Error('Failed to fetch product');
  }

  return response.json();
}

export async function createProduct(data: CreateProductRequest): Promise<{ id: string }> {
  const apiBase = await getApiBase();
  const response = await fetch(`${apiBase}/api/catalog/products`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });

