 4→function getApiBase(): Promise<string> {
 5→  if (!_configPromise) {
 6→    _configPromise =
 7→      typeof window !== "undefined"
 8→        ? fetch("/api/config")
 9→            .then((r) => r.json())
10→            .then((d) => d.apiBaseUrl as string)
11→            .catch(() => "http://localhost:5200")
12→        : Promise.resolve(
13→            process.env.NEXT_PUBLIC_API_URL || "http://localhost:5200"
14→          );
15→  }
16→  return _configPromise;
17→}
