 1→// Server-side config that reads Aspire-injected environment variables
 2→export function getApiBaseUrl(): string {
 3→  // Aspire injects gateway service URL (gateway is the API entry point)
 4→  const aspireUrl =
 5→    process.env.services__gateway__https__0 ||
 6→    process.env.services__gateway__http__0;
