112→// MassTransit with conditional transport and EF Core outbox
113→builder.Services.AddMassTransit(x =>
114→{
115→    x.AddConsumers(typeof(Program).Assembly);
116→
117→    x.AddSagaStateMachine<CheckoutStateMachine, CheckoutState>()
118→        .EntityFrameworkRepository(r =>
119→        {
120→            r.ConcurrencyMode = ConcurrencyMode.Optimistic;
121→            r.ExistingDbContext<OrderingDbContext>();
122→            r.UsePostgres();
123→        });
124→
125→    x.AddEntityFrameworkOutbox<CatalogDbContext>(o =>
126→    {
127→        o.UsePostgres();
128→        o.UseBusOutbox();
129→        o.QueryDelay = TimeSpan.FromSeconds(1);
130→        o.DuplicateDetectionWindow = TimeSpan.FromMinutes(5);
131→    });
132→
133→    x.AddConfigureEndpointsCallback((context, name, cfg) =>
134→    {
135→        // DLQ routing for Azure Service Bus endpoints
136→        if (cfg is IServiceBusReceiveEndpointConfigurator sb)
137→        {
138→            sb.ConfigureDeadLetterQueueErrorTransport();
139→        }
140→
141→        // Circuit breaker (outermost) - stops consuming after sustained failures
142→        cfg.UseCircuitBreaker(cb =>
143→        {
144→            cb.TrackingPeriod = TimeSpan.FromMinutes(1);
145→            cb.TripThreshold = 15;
146→            cb.ActiveThreshold = 10;
147→            cb.ResetInterval = TimeSpan.FromMinutes(5);
148→        });
149→
150→        // Retry with exponential backoff - PermanentException skips retries
151→        cfg.UseMessageRetry(r =>
152→        {
153→            r.Intervals(TimeSpan.FromSeconds(1), TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(25));
154→            r.Ignore<PermanentException>();
155→        });
156→
157→        // Inbox deduplication (innermost) - prevents duplicate message processing
158→        cfg.UseEntityFrameworkOutbox<CatalogDbContext>(context);
159→    });
160→
161→    if (useRabbitMq)
162→    {
163→        x.UsingRabbitMq((context, cfg) =>
164→        {
165→            cfg.Host(builder.Configuration["RabbitMQ:Host"] ?? "localhost", "/", h =>
166→            {
167→                h.Username(builder.Configuration["RabbitMQ:Username"] ?? "guest");
168→                h.Password(builder.Configuration["RabbitMQ:Password"] ?? "guest");
169→            });
170→            cfg.ConfigureEndpoints(context);
171→        });
172→    }
173→    else
174→    {
175→        x.UsingAzureServiceBus((context, cfg) =>
176→        {
177→            cfg.Host(builder.Configuration.GetConnectionString("messaging"));
178→            cfg.ConfigureEndpoints(context);
179→        });
180→    }
181→});
